script.text:

function activeForm(f) {
  initForm(f);
  f.add_onResponseComplete(on$Form$ResponseComplete);
}
function closeForm(f) {try {f.remove_onResponseComplete(on$Form$ResponseComplete);} catch (ex) {}}
function initForm(f) {
  f.getItem('ma_bp').focus();
  var location = f.getItem('ma_vi_tri');
  if (f._action != 'View') f._setReadOnly(f.getItem('ma_kho'), f._action == 'Edit' && !f.getItemValue('dv_yn'));
  location.field.AllowNulls = (location.field.Hidden || !f.getItemValue('vi_tri_yn'));
  setFormDefaultValue(f);
}
function setFormDefaultValue(f) {
  if (f._action == 'New') f.setItemValues('ma_dvcs, ten_dvcs%l', [f._unitCode, f._unitName]);
  o = f.getItem('ma_kho');
  onChangeOpeningBalanceSite(o);
}
function on$Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Site':
      var o = f.getItem('ma_vi_tri'), v = result[0].Value == 1;
      o.field.AllowNulls = (!v);
      grandNode = o.parentNode.parentNode;
      if (v) {
        Sys.UI.DomElement.addCssClass(grandNode, 'Required');
        Sys.UI.DomElement.addCssClass(grandNode, f._id);
      } else Sys.UI.DomElement.removeCssClass(grandNode, 'Required');
      break;
    case 'Loading':
      break; 
    default:
      break;
  }
}
function onChangeOpeningBalanceSite(o) {
  var f = o.parentForm;
  if (!f.getItem('ma_vi_tri').field.Hidden) {
    f.setReferenceKeyFilter('ma_vi_tri');
    f.request('Site', 'Site', ['ma_kho']);
  }
}
function controlLocationLot(f) {
  var g = f.grid;
  if (g._compactMode) {
    setObjectFormHidden(f, 'ma_vi_tri');
    setObjectFormHidden(f, 'ma_lo');
  } else if (g._tracked) {
    if (!g._tracked$Location) setObjectFormHidden(f, 'ma_vi_tri');
    if (!g._tracked$Lot) setObjectFormHidden(f, 'ma_lo');
  }
}
function setObjectFormHidden(f, c) {
  var o = f.getItem(c), field = $func.findField(c, f._fields);
  $common.setVisible(o.parentNode.parentNode.parentNode, false);
  field.Hidden = true;
}
